using System;
using System.Collections.Generic;
using System.Xml;
using System.IO;

public Dictionary<string, string> ParseConfig(string xmlFilePath)
{
    var config = new Dictionary<string, string>();
    XmlReader reader = XmlReader.Create(xmlFilePath);

    reader.MoveToContent();
    while (reader.Read())
    {
        if (reader.NodeType == XmlNodeType.Element && reader.Name == "setting")
        {
            reader.ReadStartElement("setting");
            string key = reader.GetAttribute("name");
            while (reader.MoveToNextAttribute())
            {
                if (reader.Name == "key") config[key] = reader.Value;
            }
            reader.ReadEndElement();
        }
    }

    // Add validation if required by DTDs, not shown here for brevity

    return config;
}